import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums", () => {
    it("should return 5 G for empty item list (processing fee only)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
    });
    it("should return 105 G for a plain sword (100 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }])).toBe(105);
    });
    it("should return 65 G for a plain amulet (60 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }])).toBe(65);
    });
    it("should return 85 G for a plain staff (80 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }])).toBe(85);
    });
    it("should return 45 G for a plain potion (40 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }])).toBe(45);
    });
    it("should return 30 G for a single rune (25 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }])).toBe(30);
    });
    it("should return 30 G for a single moonstone (25 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "moonstone" }])).toBe(30);
    });
  });

  describe("quote - multiple items", () => {
    it("should sum base premiums for two different main items (sword + amulet = 165 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }, { type: "amulet" }])).toBe(165);
    });
    it("should return 55 G for two runes (50 base + 5 fee)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }])).toBe(55);
    });
  });

  describe("quote - component blocks", () => {
    it("should apply block premium of 60 G for exactly 3 alike runes (65 G total)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(65);
    });
    it("should apply block premium of 60 G for exactly 3 alike moonstones (65 G total)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }])).toBe(65);
    });
    it("should not apply block for 4 runes — charge 100 G base (105 G total)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(105);
    });
    it("should apply one block + singles for 7 runes — 175 G base (180 G total)", () => {
      expect(
        quote({ yearsWithMHPCO: 0 }, [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ]),
      ).toBe(180);
    });
    it("should apply two separate blocks for 3 runes + 3 moonstones — 120 G base (125 G total)", () => {
      expect(
        quote({ yearsWithMHPCO: 0 }, [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "moonstone" },
          { type: "moonstone" },
          { type: "moonstone" },
        ]),
      ).toBe(125);
    });
    it("should not apply block for 2 runes + 1 moonstone — 75 G base (80 G total)", () => {
      expect(
        quote({ yearsWithMHPCO: 0 }, [
          { type: "rune" },
          { type: "rune" },
          { type: "moonstone" },
        ]),
      ).toBe(80);
    });
  });

  describe("quote - item-specific modifiers", () => {
    it("should add 50% curse surcharge to a cursed sword (100 + 50 + 5 = 155 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }])).toBe(155);
    });
    it("should add 30% high-enchantment surcharge to a sword with enchantment 5 (100 + 30 + 5 = 135 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 5 }])).toBe(135);
    });
    it("should not add high-enchantment surcharge to a sword with enchantment 4 (100 + 5 = 105 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 4 }])).toBe(105);
    });
    it("should add both curse and high-enchantment surcharges when both apply (100 + 50 + 30 + 5 = 185 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true, enchantment: 5 }])).toBe(185);
    });
    it("should apply curse surcharge only to the cursed item in a multi-item policy (cursed sword + plain amulet = 100+60+50+5 = 215 G)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }])).toBe(215);
    });
  });

  describe("quote - policy-wide modifiers", () => {
    it("should apply 20% loyalty discount for customer with 2 years (100 - 20 + 5 = 85 G)", () => {
      expect(quote({ yearsWithMHPCO: 2 }, [{ type: "sword" }])).toBe(85);
    });
    it("should apply 20% loyalty discount for customer with 3 years", () => {
      expect(quote({ yearsWithMHPCO: 3 }, [{ type: "sword" }])).toBe(85);
    });
    it("should not apply loyalty discount for customer with 1 year (100 + 5 = 105 G)", () => {
      expect(quote({ yearsWithMHPCO: 1 }, [{ type: "sword" }])).toBe(105);
    });
    it.todo("should apply 10% first insurance surcharge per item in a quote (100 + 10 + 5 = 115 G for one sword)");
    it.todo("should apply 15% follow-up discount on the customer's second quote (100 - 15 + 5 = 90 G base/loyalty-free)");
    it.todo("should not apply follow-up discount on the first quote");
  });

